import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  Package, 
  Plus, 
  Search, 
  Edit, 
  CheckCircle, 
  Truck, 
  XCircle,
  AlertCircle,
  RefreshCw
} from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { 
  fetchAllParcels, 
  createParcel, 
  updateParcelStatus,
  updateParcel,
  mapServerParcel 
} from '../services/api';

export default function AdminDashboard() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [parcels, setParcels] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showBookingForm, setShowBookingForm] = useState(false);
  const [selectedParcel, setSelectedParcel] = useState(null);
  const [showStatusModal, setShowStatusModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Booking form state
  const [formData, setFormData] = useState({
    senderName: '',
    senderEmail: '',
    senderPhone: '',
    receiverName: '',
    receiverPhone: '',
    sourceCity: '',
    destinationCity: '',
    serviceType: 'Speed Post',
    packageType: 'Document',
    pickupDate: '',
    weightKg: '',
    costInr: '',
    paymentMethod: 'Cash',
    notes: '',
  });

  useEffect(() => {
    if (!user || user.role !== 'admin') {
      navigate('/admin/login');
      return;
    }
    loadParcels();
  }, [user, navigate]);

  const loadParcels = async () => {
    setLoading(true);
    try {
      const data = await fetchAllParcels();
      setParcels(data.map(mapServerParcel));
    } catch (error) {
      console.error('Error loading parcels:', error);
      alert('Failed to load shipments');
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleSubmitBooking = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const response = await createParcel(formData);
      alert(`Shipment booked successfully!\nTracking ID: ${response.trackingId}\n\nPlease provide this tracking ID to the customer.`);
      setFormData({
        senderName: '',
        senderEmail: '',
        senderPhone: '',
        receiverName: '',
        receiverPhone: '',
        sourceCity: '',
        destinationCity: '',
        serviceType: 'Speed Post',
        packageType: 'Document',
        pickupDate: '',
        weightKg: '',
        costInr: '',
        paymentMethod: 'Cash',
        notes: '',
      });
      setShowBookingForm(false);
      loadParcels();
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to book shipment');
    } finally {
      setLoading(false);
    }
  };

  const handleStatusUpdate = async (status, notes = '') => {
    if (!selectedParcel) return;

    setLoading(true);
    try {
      await updateParcelStatus(selectedParcel.id, status, notes);
      alert('Status updated successfully!');
      setShowStatusModal(false);
      setSelectedParcel(null);
      loadParcels();
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to update status');
    } finally {
      setLoading(false);
    }
  };

  const getStatusBadge = (status) => {
    const badges = {
      'Pending Approval': 'bg-warning',
      Booked: 'bg-primary',
      'In Transit': 'bg-info',
      Delivered: 'bg-success',
      'On Hold': 'bg-warning',
      Cancelled: 'bg-danger',
    };
    return badges[status] || 'bg-secondary';
  };

  const filteredParcels = parcels.filter((parcel) =>
    parcel.trackingId.toLowerCase().includes(searchTerm.toLowerCase()) ||
    parcel.senderName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    parcel.receiverName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (!user || user.role !== 'admin') {
    return null;
  }

  return (
    <div className="d-flex flex-column min-vh-100 bg-light">
      {/* Header */}
      <header className="bg-white shadow-sm">
        <div className="container py-3">
          <div className="d-flex justify-content-between align-items-center">
            <div>
              <h4 className="fw-bold mb-0">Admin Dashboard</h4>
              <p className="text-muted small mb-0">Welcome, {user.name}</p>
            </div>
            <div className="d-flex gap-2">
              <button
                className="btn btn-outline-secondary btn-sm"
                onClick={() => navigate('/')}
              >
                View Website
              </button>
              <button className="btn btn-danger btn-sm" onClick={logout}>
                Logout
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-grow-1 py-4">
        <div className="container">
          {/* Stats Cards */}
          <div className="row g-3 mb-4">
            <div className="col-md-3">
              <div className="card border-0 shadow-sm">
                <div className="card-body">
                  <div className="d-flex justify-content-between align-items-center">
                    <div>
                      <p className="text-muted small mb-1">Total Shipments</p>
                      <h3 className="fw-bold mb-0">{parcels.length}</h3>
                    </div>
                    <Package className="text-primary" size={32} />
                  </div>
                </div>
              </div>
            </div>
            <div className="col-md-3">
              <div className="card border-0 shadow-sm">
                <div className="card-body">
                  <div className="d-flex justify-content-between align-items-center">
                    <div>
                      <p className="text-muted small mb-1">Pending Approval</p>
                      <h3 className="fw-bold mb-0 text-warning">
                        {parcels.filter((p) => p.status === 'Pending Approval').length}
                      </h3>
                    </div>
                    <Package className="text-warning" size={32} />
                  </div>
                </div>
              </div>
            </div>
            <div className="col-md-3">
              <div className="card border-0 shadow-sm">
                <div className="card-body">
                  <div className="d-flex justify-content-between align-items-center">
                    <div>
                      <p className="text-muted small mb-1">Booked</p>
                      <h3 className="fw-bold mb-0 text-primary">
                        {parcels.filter((p) => p.status === 'Booked').length}
                      </h3>
                    </div>
                    <Package className="text-primary" size={32} />
                  </div>
                </div>
              </div>
            </div>
            <div className="col-md-3">
              <div className="card border-0 shadow-sm">
                <div className="card-body">
                  <div className="d-flex justify-content-between align-items-center">
                    <div>
                      <p className="text-muted small mb-1">In Transit</p>
                      <h3 className="fw-bold mb-0 text-info">
                        {parcels.filter((p) => p.status === 'In Transit').length}
                      </h3>
                    </div>
                    <Truck className="text-info" size={32} />
                  </div>
                </div>
              </div>
            </div>
            <div className="col-md-3">
              <div className="card border-0 shadow-sm">
                <div className="card-body">
                  <div className="d-flex justify-content-between align-items-center">
                    <div>
                      <p className="text-muted small mb-1">Delivered</p>
                      <h3 className="fw-bold mb-0 text-success">
                        {parcels.filter((p) => p.status === 'Delivered').length}
                      </h3>
                    </div>
                    <CheckCircle className="text-success" size={32} />
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Actions Bar */}
          <div className="card border-0 shadow-sm mb-4">
            <div className="card-body">
              <div className="d-flex justify-content-between align-items-center flex-wrap gap-3">
                <div className="d-flex gap-2 flex-grow-1">
                  <div className="input-group" style={{ maxWidth: '400px' }}>
                    <span className="input-group-text bg-light">
                      <Search size={18} />
                    </span>
                    <input
                      type="text"
                      className="form-control"
                      placeholder="Search by tracking ID, sender, or receiver..."
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                </div>
                <div className="d-flex gap-2">
                  <button
                    className="btn btn-danger"
                    onClick={() => setShowBookingForm(true)}
                  >
                    <Plus size={20} className="me-2" />
                    Book New Shipment
                  </button>
                  <button
                    className="btn btn-outline-secondary"
                    onClick={loadParcels}
                    disabled={loading}
                  >
                    <RefreshCw size={20} />
                  </button>
                </div>
              </div>
            </div>
          </div>

          {/* Booking Form Modal */}
          {showBookingForm && (
            <div className="modal show d-block" tabIndex="-1" style={{ backgroundColor: 'rgba(0,0,0,0.5)' }}>
              <div className="modal-dialog modal-lg modal-dialog-scrollable" style={{ maxHeight: '90vh' }}>
                <div className="modal-content d-flex flex-column" style={{ maxHeight: '90vh' }}>
                  <div className="modal-header bg-danger text-white flex-shrink-0">
                    <h5 className="modal-title fw-bold">Book New Shipment</h5>
                    <button
                      type="button"
                      className="btn-close btn-close-white"
                      onClick={() => setShowBookingForm(false)}
                    />
                  </div>
                  <form onSubmit={handleSubmitBooking} className="d-flex flex-column" style={{ height: '100%' }}>
                    <div className="modal-body flex-grow-1" style={{ overflowY: 'auto' }}>
                      <div className="row g-3">
                        <div className="col-12">
                          <h6 className="text-muted mb-3">Sender Information</h6>
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">
                            Sender Name <span className="text-danger">*</span>
                          </label>
                          <input
                            type="text"
                            className="form-control"
                            name="senderName"
                            value={formData.senderName}
                            onChange={handleInputChange}
                            required
                          />
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">
                            Sender Phone <span className="text-danger">*</span>
                          </label>
                          <input
                            type="tel"
                            className="form-control"
                            name="senderPhone"
                            value={formData.senderPhone}
                            onChange={handleInputChange}
                            required
                          />
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">
                            Sender Email <span className="text-danger">*</span>
                          </label>
                          <input
                            type="email"
                            className="form-control"
                            name="senderEmail"
                            value={formData.senderEmail}
                            onChange={handleInputChange}
                            required
                            placeholder="customer@example.com"
                          />
                          <small className="text-muted">Tracking ID will be sent to this email</small>
                        </div>
                        <div className="col-12">
                          <h6 className="text-muted mb-3 mt-3">Receiver Information</h6>
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">
                            Receiver Name <span className="text-danger">*</span>
                          </label>
                          <input
                            type="text"
                            className="form-control"
                            name="receiverName"
                            value={formData.receiverName}
                            onChange={handleInputChange}
                            required
                          />
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">
                            Receiver Phone <span className="text-danger">*</span>
                          </label>
                          <input
                            type="tel"
                            className="form-control"
                            name="receiverPhone"
                            value={formData.receiverPhone}
                            onChange={handleInputChange}
                            required
                          />
                        </div>
                        <div className="col-12">
                          <h6 className="text-muted mb-3 mt-3">Shipment Details</h6>
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">
                            Source City <span className="text-danger">*</span>
                          </label>
                          <input
                            type="text"
                            className="form-control"
                            name="sourceCity"
                            value={formData.sourceCity}
                            onChange={handleInputChange}
                            required
                          />
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">
                            Destination City <span className="text-danger">*</span>
                          </label>
                          <input
                            type="text"
                            className="form-control"
                            name="destinationCity"
                            value={formData.destinationCity}
                            onChange={handleInputChange}
                            required
                          />
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">Service Type</label>
                          <select
                            className="form-select"
                            name="serviceType"
                            value={formData.serviceType}
                            onChange={handleInputChange}
                          >
                            <option>Speed Post</option>
                            <option>Registered Post</option>
                            <option>Parcel</option>
                            <option>Logistics</option>
                            <option>Money Order</option>
                          </select>
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">Package Type</label>
                          <select
                            className="form-select"
                            name="packageType"
                            value={formData.packageType}
                            onChange={handleInputChange}
                          >
                            <option>Document</option>
                            <option>Box</option>
                            <option>Fragile</option>
                            <option>High Value</option>
                          </select>
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">Pickup / Drop Date</label>
                          <input
                            type="date"
                            className="form-control"
                            name="pickupDate"
                            value={formData.pickupDate}
                            onChange={handleInputChange}
                          />
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">
                            Weight (kg) <span className="text-danger">*</span>
                          </label>
                          <input
                            type="number"
                            step="0.1"
                            min="0.1"
                            className="form-control"
                            name="weightKg"
                            value={formData.weightKg}
                            onChange={handleInputChange}
                            required
                          />
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">Declared Value / Estimated Cost (₹)</label>
                          <input
                            type="number"
                            min="0"
                            className="form-control"
                            name="costInr"
                            value={formData.costInr}
                            onChange={handleInputChange}
                          />
                        </div>
                        <div className="col-md-6">
                          <label className="form-label fw-semibold">Payment Method</label>
                          <select
                            className="form-select"
                            name="paymentMethod"
                            value={formData.paymentMethod}
                            onChange={handleInputChange}
                          >
                            <option>Cash</option>
                            <option>UPI</option>
                            <option>Card</option>
                            <option>Net Banking</option>
                          </select>
                        </div>
                        <div className="col-12">
                          <label className="form-label fw-semibold">Special Instructions</label>
                          <textarea
                            className="form-control"
                            rows="3"
                            name="notes"
                            value={formData.notes}
                            onChange={handleInputChange}
                            placeholder="e.g. Deliver after office hours, handle with care"
                          />
                        </div>
                      </div>
                    </div>
                    <div className="modal-footer flex-shrink-0 border-top">
                      <button
                        type="button"
                        className="btn btn-secondary"
                        onClick={() => setShowBookingForm(false)}
                        disabled={loading}
                      >
                        Cancel
                      </button>
                      <button type="submit" className="btn btn-danger" disabled={loading}>
                        {loading ? 'Booking...' : 'Book Shipment'}
                      </button>
                    </div>
                  </form>
                </div>
              </div>
            </div>
          )}

          {/* Status Update Modal */}
          {showStatusModal && selectedParcel && (
            <div className="modal show d-block" tabIndex="-1" style={{ backgroundColor: 'rgba(0,0,0,0.5)' }}>
              <div className="modal-dialog">
                <div className="modal-content">
                  <div className="modal-header">
                    <h5 className="modal-title">Update Shipment Status</h5>
                    <button
                      type="button"
                      className="btn-close"
                      onClick={() => {
                        setShowStatusModal(false);
                        setSelectedParcel(null);
                      }}
                    />
                  </div>
                  <div className="modal-body">
                    <p className="mb-3">
                      <strong>Tracking ID:</strong> {selectedParcel.trackingId}
                    </p>
                    <p className="mb-3">
                      <strong>Current Status:</strong>{' '}
                      <span className={`badge ${getStatusBadge(selectedParcel.status)}`}>
                        {selectedParcel.status}
                      </span>
                    </p>
                    <div className="d-grid gap-2">
                      {['Pending Approval', 'Booked', 'In Transit', 'Delivered', 'On Hold', 'Cancelled'].map((status) => (
                        <button
                          key={status}
                          type="button"
                          className={`btn btn-outline-${status === 'Delivered' ? 'success' : status === 'Cancelled' ? 'danger' : 'primary'}`}
                          onClick={() => handleStatusUpdate(status)}
                          disabled={selectedParcel.status === status}
                        >
                          {status}
                          {selectedParcel.status === status && ' (Current)'}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Parcels Table */}
          <div className="card border-0 shadow-sm">
            <div className="card-body">
              <h5 className="fw-bold mb-4">All Shipments</h5>
              {loading && !parcels.length ? (
                <div className="text-center py-5">
                  <div className="spinner-border text-danger" role="status">
                    <span className="visually-hidden">Loading...</span>
                  </div>
                </div>
              ) : filteredParcels.length === 0 ? (
                <div className="text-center py-5 text-muted">
                  <Package size={48} className="mb-3 opacity-50" />
                  <p>No shipments found</p>
                </div>
              ) : (
                <div className="table-responsive">
                  <table className="table table-hover">
                    <thead>
                      <tr>
                        <th>Tracking ID</th>
                        <th>Sender</th>
                        <th>Receiver</th>
                        <th>Route</th>
                        <th>Service</th>
                        <th>Weight</th>
                        <th>Cost</th>
                        <th>Status</th>
                        <th>Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredParcels.map((parcel) => (
                        <tr key={parcel.id}>
                          <td>
                            <code className="text-danger fw-bold">{parcel.trackingId}</code>
                          </td>
                          <td>
                            <div>{parcel.senderName}</div>
                            <small className="text-muted">{parcel.senderPhone}</small>
                          </td>
                          <td>
                            <div>{parcel.receiverName}</div>
                            <small className="text-muted">{parcel.receiverPhone}</small>
                          </td>
                          <td>
                            <div>{parcel.sourceCity}</div>
                            <small className="text-muted">→ {parcel.destinationCity}</small>
                          </td>
                          <td>
                            <span className="badge bg-secondary">{parcel.serviceType}</span>
                          </td>
                          <td>{parcel.weightKg} kg</td>
                          <td>₹{parcel.costInr}</td>
                          <td>
                            <span className={`badge ${getStatusBadge(parcel.status)}`}>
                              {parcel.status}
                            </span>
                          </td>
                          <td>
                            <button
                              className="btn btn-sm btn-outline-primary"
                              onClick={() => {
                                setSelectedParcel(parcel);
                                setShowStatusModal(true);
                              }}
                            >
                              <Edit size={16} />
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
